1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation, 0 neighbors)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (underpopulation, 1 neighbor each)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("Rule 2 - Survival: center cell with 3 live neighbors survives", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [2, 0]])).toContainEqual([1, 0]);
16	  });
17	  it.todo("Rule 3 - Overpopulation: center cell with 4 live neighbors dies");
18	  it.todo("Rule 4 - Reproduction: dead cell with exactly 3 live neighbors becomes alive");
19	  it.todo("Block (still life): 2x2 block remains unchanged");
20	  it.todo("Blinker (oscillator): vertical blinker becomes horizontal blinker");
21	});
