1	export function nextGeneration(grid: number[][]): number[][] {
2	  const key = (x: number, y: number) => `${x},${y}`;
3	  const live = new Set(grid.map(([x, y]) => key(x, y)));
4	  const neighborCounts = new Map<string, number>();
5	
6	  for (const [x, y] of grid) {
7	    for (let dx = -1; dx <= 1; dx++) {
8	      for (let dy = -1; dy <= 1; dy++) {
9	        if (dx === 0 && dy === 0) continue;
10	        const k = key(x + dx, y + dy);
11	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
12	      }
13	    }
14	  }
15	
16	  const nextLive: number[][] = [];
17	  for (const [k, count] of neighborCounts) {
18	    const isAlive = live.has(k);
19	    if (count === 3 || (isAlive && count === 2)) {
20	      const [x, y] = k.split(",").map(Number);
21	      nextLive.push([x, y]);
22	    }
23	  }
24	  return nextLive;
25	}
